# Get all ki-llm articles
data = read_file(path="C:\\HermesPortable\\home\\spaces\\hostazar\\data\\artikel.json")
lines = data['content'].split('\n')

ki_articles = []
current = None
for line in lines:
    if '"slug"' in line:
        if current: ki_articles.append(current)
        current = {'slug': line.split('"')[3]}
    if current and '"category"' in line:
        current['category'] = line.split('"')[3]
    if current and '"image"' in line:
        current['image'] = line.split('"')[3]
    if current and '"title"' in line:
        current['title'] = line.split('"')[3]
if current: ki_articles.append(current)

ki_articles = [a for a in ki_articles if a.get('category') == 'ki-llm']
print(f"KI-LLM articles ({len(ki_articles)}):")
for a in ki_articles:
    print(f"  {a['slug']} -> images/{a['image']}")

# Check what image files exist
import os
img_dir = "C:\\HermesPortable\\home\\spaces\\hostazar\\images"
print(f"\nExisting images:")
for a in ki_articles:
    path = os.path.join(img_dir, a['image'])
    exists = os.path.exists(path)
    size = os.path.getsize(path) if exists else 0
    print(f"  {a['image']}: {'EXISTS' if exists else 'MISSING'} ({size} bytes)")

# Check names with ß vs ss issue
print("\nLooking for images with similar names...")
for f in os.listdir(img_dir):
    if any(word in f.lower() for word in ['llm', 'cuda', 'gpu', 'ki-', 'openai', 'ollama', 'llama', 'quantisierung', 'inferenz', 'vllm']):
        print(f"  {f}")"}

